#define MAX        100000
#define NULL_CARRY -1
#define NULL_VALUE 0

LLI h1, h2;

int carry[4 * MAX];
int st[4 * MAX];
int en[4 * MAX];
LLI ans[2][4 * MAX];


void init2(int index, int s, int e) {
   //printf("%d %d %d\n", index, s, e);
   st[index] = s;
   en[index] = e;
   ans[0][index] = 0;
   ans[1][index] = 0;
   carry[index] = NULL_CARRY;
   if (s == e)
      return;
   int mid = (s + e) >> 1;
   init2(index << 1, s, mid);
   init2((index << 1) | 1, mid + 1, e);
}

// Inclusive s and e
void ITInit(int s, int e) {
   init2(1, s, e);
}

LLI fastExpo(LLI exp, LLI base, LLI mod) {
    if (exp == 0)
        return 1;
    if (exp == 1)
        return base % mod;
    LLI tmp = fastExpo(exp >> 1, base, mod);
    tmp *= tmp;
    tmp %= mod; 
    if (exp & 1)
        tmp = (tmp * base) % mod;
    return tmp;
}


LLI aoMem[2][MAX + 10];
LLI feMem[2][MAX + 10];
void genAllOnes() {
    int i;
    LLI tmp1 = 0;
    LLI tmp2 = 0;
    LLI tmp3 = 1;
    LLI tmp4 = 1;
    fo3(i,0, MAX+9) {
        aoMem[TRUE][i] = tmp1;
        tmp1 = tmp1 * 10 + 1;
        tmp1 %= h1;
        aoMem[FALSE][i] = tmp2;
        tmp2 = tmp2 * 10 + 1;
        tmp2 %= h2;
        feMem[TRUE][i] = tmp3;
        tmp3 *= 10;
        tmp3 %= h1;
        feMem[FALSE][i] = tmp4;
        tmp4 *= 10;
        tmp4 %= h2;
    }
}
LLI allOnes(int len, LLI mod) {
    return aoMem[mod==h1][len];
}

LLI agg(int pre, int suf, int pow, LLI mod) {
    LLI mult = feMem[mod==h1][pow];
    mult *= suf;
    mult += pre;
    mult %= mod;
    //printf(" returning from agg!\n");
    return mult;
}

void ITComp(int index) {
    if (carry[index] == NULL_CARRY) {
        ans[0][index] = agg(ans[0][index<<1], ans[0][(index<<1)|1], en[index<<1] - st[index<<1] + 1, h1);
        ans[1][index] = agg(ans[1][index<<1], ans[1][(index<<1)|1], en[index<<1] - st[index<<1] + 1, h2);
    } else {
        ans[0][index] = allOnes(en[index] - st[index] + 1, h1) * carry[index];
        ans[0][index] %= h1;
        ans[1][index] = allOnes(en[index] - st[index] + 1, h2) * carry[index];
        ans[1][index] %= h2;
    }
}

void push(int index) {
    if (carry[index] == NULL_CARRY)
        return;
    if (st[index] != en[index]) {
        carry[index<<1] = carry[index];
        ITComp(index<<1);
        carry[(index<<1)|1] = carry[index];
        ITComp((index<<1)|1);
    }
    carry[index] = NULL_CARRY;
}


void set2(int index, int s, int e, int value) {
    if (st[index] >= s && e >= en[index]) {
        carry[index] = value;
        ITComp(index);
        return;
    }
    if (st[index] > e || s > en[index])
        return;
    push(index);
    set2(index<<1, s, e, value);
    set2((index<<1)|1, s, e, value);
    ITComp(index);
}

void ITSet(int s, int e, int value) {
   set2(1, s, e, value);
}

LLI get2(int index, int type, int s, int e) {
    if (st[index] >= s && e >= en[index]) {
        //printf(" Starting Push!\n");
        //push(index);
        ITComp(index);
        //printf(" Out of Push!\n");
        if (type == 0) {
            //prL(agg(0, ans[type][index], st[index] - s, h1));
            return agg(0, ans[type][index], st[index] - s, h1);
        }            
        return agg(0, ans[type][index], st[index] - s, h2);
    }
    if (st[index] > e || s > en[index])
        return NULL_VALUE;
    push(index);
    LLI ret = get2(index<<1, type, s, e) + get2((index<<1)|1, type, s, e);
    if (type == 0 && ret >= h1)
        ret -= h1;
    if (type == 1 && ret >= h2)
        ret -= h2;
    return ret;
}

LLI get(int type, int s, int e) {
   return get2(1, type, s, e);
}

#define MOD 1000000007

LLI ch2(int x) {
    return (x * (x - 1)) >> 1;
}

void make(int n, int spots, LLI ** mat) {
    int i, j;
    int totalSmaller = spots - 1;
    int totalBigger = n - totalSmaller;
    LLI total = ch2(n);
    fo3(i,0,spots-1) {
        fo3(j,0,spots-1) {
            int smallerCorrect = i;
            int smallerIncorrect = totalSmaller - smallerCorrect;
            int biggerIncorrect = smallerIncorrect;
            int biggerCorrect = totalBigger - biggerIncorrect;
            if (i + 1 < j || j + 1 < i)
                mat[i][j] = 0;
            else if (i == j) {
                mat[i][j] = (total - (smallerCorrect * biggerCorrect + smallerIncorrect * biggerIncorrect)) % MOD;
            } else if (j < i) {
                // Worse
                mat[i][j] = (smallerCorrect * biggerCorrect) % MOD; 
            } else {
                // Better
                mat[i][j] = (smallerIncorrect * biggerIncorrect) % MOD; 
            }
        }
    }
}

LLI ** ident;



void clean2(LLI ** mat, int dim) { 
    int i;
    fo3(i,0,dim-1)
        free(mat[i]);
    free(mat);
}

LLI ** mult(LLI ** a, LLI ** b, int dim) {
    LLI ** ret;
    int i, j, k;
    ret = calloc(dim, sizeof(LLI*));
    fo3(i,0,dim-1){
        ret[i] = calloc(dim, sizeof(LLI));
        fo3(j,0,dim-1){
            ret[i][j] = 0;
            fo3(k,0,dim-1) {
                ret[i][j] += (a[i][k] * b[k][j]) % MOD;
            }
            ret[i][j] %= MOD;
        }
    }
    return ret;
}

LLI ** expo(LLI ** base, int pow, int dim) {
    if (pow == 0) {
        return mult(ident, ident, dim);
    }
    if (pow == 1) {
        return mult(ident, base, dim);
    }
    LLI ** tmp = expo(base, pow >> 1, dim);
    LLI ** tmp2 = mult(tmp, tmp, dim);
    clean2(tmp, dim);
    if (pow&1) {
        tmp = mult(tmp2, base, dim);
        clean2(tmp2, dim);
        tmp2 = tmp;
    }
    return tmp2;
}

LLI expo2(LLI base, int pow) {
    if (pow == 0)
        return 1;
    if (pow == 1)
        return base % MOD;
    LLI tmp = expo2(base, pow>>1);
    tmp *= tmp;
    tmp %= MOD;
    if (pow&1) {
        tmp *= base;
        tmp %= MOD;
    }
    return tmp;
}


LLI inv(LLI val) {
    if (val == 1)
        return 1;
    return MOD - ((MOD / val) * inv(MOD % val)) % MOD;
}

int main(void) {
    LLI ** orig;
    int len, pow, i, j;
    in2(len, pow);
    int arr[len];
    int cs[2];
    cs[0] = 0;
    cs[1] = 0;

    fo3(i,1,len) {
        in1(arr[i-1]);
        cs[arr[i-1]]++;
    }
    int dim = cs[0] + 1;
    if (cs[1] < cs[0])
        dim = cs[1] + 1;
    orig = calloc(dim, sizeof(LLI*));
    fo3(i,0,dim-1)
        orig[i] = calloc(dim, sizeof(LLI));
    ident = calloc(dim, sizeof(LLI*));
    fo3(i,0,dim-1){
        ident[i] = calloc(dim, sizeof(LLI));
        fo3(j,0,dim-1)
            ident[i][j] = ((i==j) ? 1 : 0);
    }
    make(len, dim, orig);

    LLI ** ret = expo(orig, pow, dim);
    clean2(orig, dim);
    int wrong = 0;
    fo3(i,0,cs[0]-1)
        if (arr[i]!=0)
            wrong++;
    int cor = dim - wrong - 1;
    LLI ans = ret[cor][dim - 1];
    clean2(ret, dim);
    LLI den = expo2(ch2(len), pow);
    //prL(ans);
    //prL(den);
    ans *= inv(den);
    ans %= MOD;
    prL(ans);
    return 0;
}

